1	"use client";
2	
3	import { useEffect, useState } from "react";
4	import { createClient } from "@/lib/supabase/client";
5	import { formatBytes, formatPercent, cn } from "@/lib/utils";
6	import { HardDrive, Thermometer } from "lucide-react";
7	
8	interface StorageData {
9	  volume_id: string;
10	  volume_path: string;
11	  total_bytes: number;
12	  used_bytes: number;
13	  status: string;
14	  raid_type: string;
15	  disks: {
16	    id: string;
17	    name: string;
18	    model: string;
19	    temperature_c: number;
20	    smart_status: string;
21	  }[];
22	  nas_name: string;
23	}
24	
25	export default function StoragePage() {
26	  const [volumes, setVolumes] = useState<StorageData[]>([]);
27	  const [loading, setLoading] = useState(true);
28	
29	  useEffect(() => {
30	    async function fetch() {
31	      const supabase = createClient();
32	
33	      // Get latest snapshot per volume
34	      const { data, error } = await supabase
35	        .from("storage_snapshots")
36	        .select("*, nas_units!inner(name)")
37	        .order("recorded_at", { ascending: false })
38	        .limit(20);
39	
40	      if (!error && data) {
41	        // Dedupe by volume_id (keep latest)
42	        const seen = new Set<string>();
43	        const deduped: StorageData[] = [];
44	        for (const row of data) {
45	          if (!seen.has(row.volume_id)) {
46	            seen.add(row.volume_id);
47	            deduped.push({
48	              ...row,
49	              nas_name: (row.nas_units as any)?.name ?? "Unknown",
50	            });
51	          }
52	        }
53	        setVolumes(deduped);
54	      }
55	      setLoading(false);
56	    }
57	    fetch();
58	  }, []);
59	
60	  if (loading) {
61	    return <div className="text-sm text-muted-foreground">Loading storage data...</div>;
62	  }
63	
64	  return (
65	    <div className="space-y-6">
66	      <h1 className="text-2xl font-bold">Storage</h1>
67	
68	      {volumes.length === 0 ? (
69	        <div className="rounded-lg border border-border p-8 text-center text-muted-foreground">
70	          No storage data available yet. Waiting for agent data.
71	        </div>
72	      ) : (
73	        <div className="space-y-4">
74	          {volumes.map((vol) => {
75	            const usedPct = (vol.used_bytes / vol.total_bytes) * 100;
76	            const isCritical = usedPct >= 90;
77	            const isWarning = usedPct >= 70;
78	
79	            return (
80	              <div key={vol.volume_id} className="rounded-lg border border-border bg-card p-5">
81	                <div className="flex items-center justify-between mb-3">
82	                  <div className="flex items-center gap-2">
83	                    <HardDrive className="h-5 w-5 text-muted-foreground" />
84	                    <h3 className="font-semibold">
85	                      {vol.volume_path} <span className="text-muted-foreground font-normal">({vol.nas_name})</span>
86	                    </h3>
87	                  </div>
88	                  <div className="flex items-center gap-3">
89	                    <span className="text-xs text-muted-foreground">{vol.raid_type}</span>
90	                    <span
91	                      className={cn(
92	                        "rounded-full px-2 py-0.5 text-xs font-medium",
93	                        vol.status === "normal"
94	                          ? "bg-success/10 text-success"
95	                          : vol.status === "degraded"
96	                          ? "bg-warning/10 text-warning"
97	                          : "bg-destructive/10 text-destructive"
98	                      )}
99	                    >
100	                      {vol.status}
101	                    </span>
102	                  </div>
103	                </div>
104	
105	                {/* Usage bar */}
106	                <div className="mb-2 flex items-center justify-between text-sm">
107	                  <span className="text-muted-foreground">
108	                    {formatBytes(vol.used_bytes)} / {formatBytes(vol.total_bytes)}
109	                  </span>
110	                  <span
111	                    className={cn(
112	                      "font-mono font-semibold",
113	                      isCritical ? "text-critical" : isWarning ? "text-warning" : "text-success"
114	                    )}
115	                  >
116	                    {formatPercent(usedPct)}
117	                  </span>
118	                </div>
119	                <div className="h-3 w-full rounded-full bg-muted">
120	                  <div
121	                    className={cn(
122	                      "h-full rounded-full transition-all",
123	                      isCritical ? "bg-critical" : isWarning ? "bg-warning" : "bg-success"
124	                    )}
125	                    style={{ width: `${usedPct}%` }}
126	                  />
127	                </div>
128	
129	                {/* Disk details */}
130	                {vol.disks && vol.disks.length > 0 && (
131	                  <div className="mt-4 grid grid-cols-2 gap-2">
132	                    {vol.disks.map((disk) => (
133	                      <div
134	                        key={disk.id}
135	                        className="flex items-center justify-between rounded-md bg-muted/50 px-3 py-2 text-sm"
136	                      >
137	                        <div>
138	                          <span className="font-medium">{disk.name}</span>
139	                          <span className="ml-2 text-muted-foreground">{disk.model}</span>
140	                        </div>
141	                        <div className="flex items-center gap-3">
142	                          <div className="flex items-center gap-1">
143	                            <Thermometer className="h-3.5 w-3.5 text-muted-foreground" />
144	                            <span className={cn(
145	                              "font-mono",
146	                              disk.temperature_c > 50 ? "text-critical" :
147	                              disk.temperature_c > 40 ? "text-warning" : "text-muted-foreground"
148	                            )}>
149	                              {disk.temperature_c}C
150	                            </span>
151	                          </div>
152	                          <span
153	                            className={cn(
154	                              "text-xs",
155	                              disk.smart_status === "healthy"
156	                                ? "text-success"
157	                                : "text-warning"
158	                            )}
159	                          >
160	                            {disk.smart_status}
161	                          </span>
162	                        </div>
163	                      </div>
164	                    ))}
165	                  </div>
166	                )}
167	              </div>
168	            );
169	          })}
170	        </div>
171	      )}
172	    </div>
173	  );
174	}
