18	const ranges = ["1h", "6h", "24h", "7d", "30d"] as const;
19	
20	const metricGroups = [
21	  {
22	    title: "CPU & Load",
23	    metrics: ["cpu_usage", "cpu_iowait_pct", "system_load_1", "system_load_5"],
