101	function useDiskIO(nasId: string | null, range: (typeof ranges)[number]) {
102	  const [devices, setDevices] = useState<DiskIODevice[]>([]);
103	  const [deviceHealth, setDeviceHealth] = useState<DeviceHealth[]>([]);
104	  const [topByIO, setTopByIO] = useState<TopProcess[]>([]);
105	  const [topByCPU, setTopByCPU] = useState<TopProcess[]>([]);
106	  const [loading, setLoading] = useState(true);
107	  const [dataAge, setDataAge] = useState<string | null>(null);
108	
109	  const fetch = useCallback(async () => {
110	    if (!nasId) return;
111	    setLoading(true);
112	
113	    const supabase = createClient();
114	    const from = new Date(Date.now() - parseRange(range)).toISOString();
115	
116	    // Fetch disk I/O stats with saturation metrics
117	    const { data: ioRows } = await supabase
118	      .from("disk_io_stats")
119	      .select("captured_at, device, volume_path, read_bps, write_bps, util_pct, await_ms, queue_depth, reads_ps, writes_ps")
120	      .eq("nas_id", nasId)
121	      .gte("captured_at", from)
122	      .order("captured_at", { ascending: true })
123	      .limit(2000);
124	
125	    const deviceMap = new Map<string, DiskIODevice>();
126	    const latestPerDevice = new Map<string, DeviceHealth>();
127	
128	    for (const row of ioRows ?? []) {
129	      if (!deviceMap.has(row.device)) {
130	        deviceMap.set(row.device, {
131	          device: row.device,
132	          volume_path: row.volume_path,
133	          points: [],
134	        });
135	      }
136	      deviceMap.get(row.device)!.points.push({
137	        time: new Date(row.captured_at).getTime(),
138	        read_bps: row.read_bps ?? 0,
139	        write_bps: row.write_bps ?? 0,
140	        util_pct: row.util_pct ?? 0,
141	        await_ms: row.await_ms ?? 0,
142	        queue_depth: row.queue_depth ?? 0,
143	      });
144	      // Rows are asc by time so the last write for each device is the latest
145	      latestPerDevice.set(row.device, {
146	        device: row.device,
