269	// Merge per-device util_pct into a single time series for a multi-line chart.
270	function mergeDeviceUtil(devices: DiskIODevice[]): Record<string, number>[] {
271	  const byTime = new Map<number, Record<string, number>>();
272	
273	  for (const dev of devices) {
274	    for (const pt of dev.points) {
275	      const bucket = Math.round(pt.time / 15000) * 15000;
276	      const existing = byTime.get(bucket) ?? { time: bucket };
277	      existing[dev.device] = pt.util_pct;
278	      byTime.set(bucket, existing);
279	    }
280	  }
281	
282	  return Array.from(byTime.values()).sort((a, b) => (a.time as number) - (b.time as number));
283	}
