886	  const seconds = Math.floor((Date.now() - new Date(capturedAt).getTime()) / 1000);
887	  if (seconds < 60) return `${seconds}s ago`;
888	  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`;
